#include <iostream>
using namespace std;

int gcd(int a, int b)
{
    while (b != 0)
    {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int lcm(int a, int b)
{
    return (a * b) / gcd(a, b);
}

int main()
{
    int num1 = 48, num2 = 18;

    cout << "Sayilar: " << num1 << " ve " << num2 << endl;
    cout << "EBOB (GCD): " << gcd(num1, num2) << endl;
    cout << "EKOK (LCM): " << lcm(num1, num2) << endl;

    // Birden fazla cift icin tablo
    cout << "\nFarkli sayi ciftleri:" << endl;
    int pairs[4][2] = {{12, 18}, {7, 13}, {100, 75}, {24, 36}};

    for (int i = 0; i < 4; i++)
    {
        int a = pairs[i][0];
        int b = pairs[i][1];
        cout << "GCD(" << a << "," << b << ") = " << gcd(a, b)
             << ", LCM(" << a << "," << b << ") = " << lcm(a, b) << endl;
    }

    return 0;
}
